import React, { useEffect, useState } from "react";

// 🔗 Backend base URL
const apiBase =
  process.env.REACT_APP_API_URL || "https://prasa-app-yde3.onrender.com";

const AddTicket = ({ employee }) => {
  const [form, setForm] = useState({
    ticket_date: "",
    purpose: "",
    assigned_to: "",
    amount: "",
    status: "Pending",
  });

  const [ticketList, setTicketList] = useState([]);
  const [loading, setLoading] = useState(false);
  const [editingId, setEditingId] = useState(null); // ticket_id
  const [message, setMessage] = useState("");

  const empld = employee?.empld || employee?.emp_code || employee?.login_id;

  const loadTickets = async () => {
    if (!empld) return;
    try {
      setLoading(true);
      const res = await fetch(`${apiBase}/ticket-expenses?empld=${encodeURIComponent(empld)}`);
      if (!res.ok) throw new Error("Server error");
      const data = await res.json();
      setTicketList(data || []);
      setMessage("");
    } catch (err) {
      console.error("Load tickets error:", err);
      setMessage("❌ Could not load ticket expenses. Check server.");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadTickets();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [empld]);

  const handleChange = (field, value) => {
    setForm((prev) => ({ ...prev, [field]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setMessage("");

    if (!empld) {
      setMessage("❌ Missing employee ID");
      return;
    }

    try {
      const url =
        editingId == null
          ? `${apiBase}/ticket-expenses`
          : `${apiBase}/ticket-expenses/${editingId}`;
      const method = editingId == null ? "POST" : "PUT";

      const body = {
        empld,
        ticket_date: form.ticket_date,
        purpose: form.purpose,
        assigned_to: form.assigned_to,
        amount: parseFloat(form.amount || 0),
        status: form.status || "Pending",
      };

      const res = await fetch(url, {
        method,
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(body),
      });

      const data = await res.json();
      if (!data.success) {
        setMessage("❌ " + (data.message || "Failed to save ticket expense"));
      } else {
        setMessage(
          editingId == null
            ? "✅ Ticket expense added."
            : "✅ Ticket expense updated."
        );
        setEditingId(null);
        setForm({
          ticket_date: "",
          purpose: "",
          assigned_to: "",
          amount: "",
          status: "Pending",
        });
        loadTickets();
      }
    } catch (err) {
      console.error("Submit ticket error:", err);
      setMessage("❌ Server error while saving ticket expense.");
    }
  };

  const startEdit = (row) => {
    setEditingId(row.ticket_id);
    setForm({
      ticket_date: row.ticket_date ? row.ticket_date.substring(0, 10) : "",
      purpose: row.purpose || "",
      assigned_to: row.assigned_to || "",
      amount: String(row.amount || ""),
      status: row.status || "Pending",
    });
  };

  const deleteRow = async (row) => {
    if (!window.confirm("Delete this ticket expense?")) return;
    try {
      const res = await fetch(`${apiBase}/ticket-expenses/${row.ticket_id}`, {
        method: "DELETE",
      });
      const data = await res.json();
      if (!data.success) {
        setMessage("❌ " + (data.message || "Failed to delete."));
      } else {
        setMessage("✅ Ticket expense deleted.");
        loadTickets();
      }
    } catch (err) {
      console.error("Delete ticket error:", err);
      setMessage("❌ Server error while deleting.");
    }
  };

  return (
    <div className="add-expense-page">
      <h2>Ticket Expense</h2>

      {/* FORM */}
      <form className="expense-form" onSubmit={handleSubmit}>
        <div className="form-row">
          <label>Date</label>
          <input
            type="date"
            value={form.ticket_date}
            onChange={(e) => handleChange("ticket_date", e.target.value)}
            required
          />
        </div>

        <div className="form-row">
          <label>Purpose</label>
          <input
            type="text"
            value={form.purpose}
            onChange={(e) => handleChange("purpose", e.target.value)}
            required
          />
        </div>

        <div className="form-row">
          <label>Assigned To</label>
          <input
            type="text"
            value={form.assigned_to}
            onChange={(e) => handleChange("assigned_to", e.target.value)}
          />
        </div>

        <div className="form-row">
          <label>Amount (₹)</label>
          <input
            type="number"
            value={form.amount}
            onChange={(e) => handleChange("amount", e.target.value)}
            required
          />
        </div>

        <div className="form-row">
          <label>Status</label>
          <select
            value={form.status}
            onChange={(e) => handleChange("status", e.target.value)}
          >
            <option value="Pending">Pending</option>
            <option value="Approved">Approved</option>
            <option value="Rejected">Rejected</option>
          </select>
        </div>

        <button type="submit" className="btn-primary">
          {editingId ? "Save Changes" : "Add Ticket Expense"}
        </button>
      </form>

      {message && <p className="status-message">{message}</p>}

      {/* HISTORY TABLE */}
      <h3>Ticket Expense History</h3>

      {loading ? (
        <p>Loading...</p>
      ) : ticketList.length === 0 ? (
        <p>No ticket expenses found.</p>
      ) : (
        <table className="expense-table">
          <thead>
            <tr>
              <th>Date</th>
              <th>Purpose</th>
              <th>Assigned To</th>
              <th>Amount</th>
              <th>Status</th>
              <th style={{ width: 130 }}>Actions</th>
            </tr>
          </thead>
          <tbody>
            {ticketList.map((row) => (
              <tr key={row.ticket_id}>
                <td>{row.ticket_date?.substring(0, 10)}</td>
                <td>{row.purpose}</td>
                <td>{row.assigned_to}</td>
                <td>₹{row.amount}</td>
                <td>{row.status || "Pending"}</td>
                <td>
                  <button
                    type="button"
                    className="btn-link"
                    onClick={() => startEdit(row)}
                  >
                    Edit
                  </button>
                  <button
                    type="button"
                    className="btn-link danger"
                    onClick={() => deleteRow(row)}
                  >
                    Delete
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
};

export default AddTicket;
